"use client";

import { useStackshift } from "@/store";
import type { StepKey } from "@/types";

const STEPS: { key: StepKey; label: string; hint: string }[] = [
  { key: "url",     label: "URL",     hint: "Scan a page" },
  { key: "detect",  label: "Detect",  hint: "Review blocks" },
  { key: "match",   label: "Match",   hint: "Map content types" },
  { key: "page",    label: "Page",    hint: "Select page type" },
  { key: "preview", label: "Preview", hint: "Edit & verify" },
  { key: "done",    label: "Migrate", hint: "Push to stack" },
];

export default function Stepper() {
  const currentStep = useStackshift((s) => s.currentStep);
  const setStep = useStackshift((s) => s.setStep);
  const currentIndex = STEPS.findIndex((s) => s.key === currentStep);

  return (
    <nav className="flex items-stretch flex-wrap gap-0 mb-12 font-mono text-[11px] uppercase tracking-[1.5px]" aria-label="Migration steps">
      {STEPS.map((step, i) => {
        const isDone   = i < currentIndex;
        const isActive = i === currentIndex;
        const clickable = i <= currentIndex;

        const pillCls = [
          "inline-flex flex-col items-start gap-0.5 px-4 py-2.5 border border-line cursor-pointer transition-all duration-150 text-left min-w-[132px] font-mono rounded-none disabled:opacity-75 disabled:cursor-default",
          isDone   ? "bg-ink text-paper border-ink hover:bg-ink-soft" : "",
          isActive ? "bg-accent text-paper border-accent -translate-y-0.5 shadow-step-active" : "",
          !isDone && !isActive ? "bg-paper text-ink hover:enabled:bg-paper-2" : "",
        ].filter(Boolean).join(" ");

        return (
          <span key={step.key} className="inline-flex items-center">
            <button
              type="button"
              className={pillCls}
              onClick={() => clickable && setStep(step.key)}
              disabled={!clickable}
              aria-current={isActive ? "step" : undefined}
            >
              <span className="font-semibold text-[10px] opacity-75 tracking-[1.2px]">0{i + 1}</span>
              <span className="text-[13px] font-semibold tracking-[0.5px] normal-case font-sans">{step.label}</span>
              <span className="text-[9.5px] tracking-[1.5px] opacity-70">{step.hint}</span>
            </button>
            {i < STEPS.length - 1 && (
              <span className="flex-none w-6 h-px bg-line" />
            )}
          </span>
        );
      })}
    </nav>
  );
}
