"use client";

import { useState } from "react";
import { ScanLine, AlertCircle } from "lucide-react";
import { useStackshift } from "@/store";
import type { ScrapeResponse } from "@/types";

const inputLarge = "w-full px-5 py-[18px] font-mono text-lg border border-line bg-paper outline-none transition-all duration-150 text-ink rounded-[3px] hover:bg-card focus:border-accent focus:bg-card focus:shadow-focus";
const labelCls   = "font-mono text-[10px] uppercase tracking-[2px] text-muted block mb-2";
const btnPrimary = "inline-flex items-center gap-2.5 px-[22px] py-[13px] bg-accent border border-accent text-paper font-sans font-medium text-sm cursor-pointer transition-all duration-[120ms] rounded-[3px] hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-accent-2 disabled:opacity-45 disabled:cursor-not-allowed disabled:pointer-events-none";

export default function UrlStep() {
  const url          = useStackshift((s) => s.url);
  const dryRun       = useStackshift((s) => s.dryRun);
  const uploadAssets = useStackshift((s) => s.uploadAssets);
  const setUrl       = useStackshift((s) => s.setUrl);
  const setDryRun    = useStackshift((s) => s.setDryRun);
  const setUploadAssets = useStackshift((s) => s.setUploadAssets);
  const setComponents   = useStackshift((s) => s.setComponents);
  const setStep         = useStackshift((s) => s.setStep);

  const [scanning, setScanning] = useState(false);
  const [err, setErr]           = useState<string | null>(null);

  const handleScan = async () => {
    setErr(null);
    if (!url.trim()) { setErr("Enter a URL first."); return; }
    setScanning(true);
    try {
      const res  = await fetch("/api/scrape", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ url }) });
      const data = (await res.json()) as ScrapeResponse;
      if (!data.ok) { setErr(data.error ?? "Scan failed."); return; }
      if (!data.components.length) { setErr("No components detected. Try a more content-rich URL."); return; }
      setComponents(data.components);
      setStep("detect");
    } catch (e) {
      setErr(e instanceof Error ? e.message : "Network error.");
    } finally { setScanning(false); }
  };

  return (
    <>
      <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
        <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">02 / URL</span>
        <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
          Paste a URL. We&rsquo;ll <em className="italic font-normal text-accent">read the room</em>.
        </h2>
      </div>
      <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
        Any public webpage. We fetch the raw HTML server-side, then run heuristics to tease out reusable blocks — hero sections, card grids, FAQs, testimonials.
      </p>

      {/* browser frame card */}
      <div className="bg-card border border-line shadow-hard rounded-[3px] overflow-hidden transition-all duration-[180ms] hover:-translate-x-px hover:-translate-y-px hover:shadow-hard-hover">
        {/* frame bar */}
        <div className="flex items-center gap-2.5 px-4 py-[11px] bg-paper-2 border-b border-line font-mono text-[11px] text-muted">
          <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#ff5f57]" />
          <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#febc2e]" />
          <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#28c840]" />
          <span className="flex-1 bg-card border border-line px-2.5 py-[5px] rounded-[2px] ml-3 overflow-hidden text-ellipsis whitespace-nowrap">
            {url || "https://…"}
          </span>
        </div>

        {/* frame body */}
        <div className="p-11">
          <label className={labelCls}>URL to migrate</label>
          <input
            className={inputLarge}
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            placeholder="https://www.example.com/pricing"
            onKeyDown={(e) => { if (e.key === "Enter" && !scanning) handleScan(); }}
            spellCheck={false}
          />

          <div className="text-sm text-muted mt-3 flex gap-4 flex-wrap">
            {["Public pages only (no auth walls)", "Puppeteer / JS-rendered sites are v2", "Heuristics-only detection"].map((t) => (
              <span key={t} className="inline-flex items-center gap-1.5">
                <span className="text-accent font-semibold">›</span> {t}
              </span>
            ))}
          </div>

          <div className="mt-7 flex gap-6 items-center flex-wrap">
            <Checkbox checked={dryRun} onChange={() => setDryRun(!dryRun)}>
              Dry-run mode{" "}
              <span className="font-mono text-[11px] text-muted tracking-[1px] uppercase">— preview JSON, don&rsquo;t push</span>
            </Checkbox>
            <Checkbox checked={uploadAssets} onChange={() => setUploadAssets(!uploadAssets)}>
              Upload images as assets
            </Checkbox>
          </div>

          <div className="mt-8 flex gap-3 items-center flex-wrap">
            <button className={btnPrimary} onClick={handleScan} disabled={scanning || !url.trim()}>
              {scanning
                ? <><span className="inline-block w-3.5 h-3.5 rounded-full border-2 border-paper-2 border-t-accent animate-spin" /> Scanning…</>
                : <><ScanLine size={14} /> Scan page</>}
            </button>
            {err && (
              <span className="text-accent text-sm inline-flex items-center gap-1.5">
                <AlertCircle size={14} /> {err}
              </span>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

function Checkbox({ checked, onChange, children }: { checked: boolean; onChange: () => void; children: React.ReactNode }) {
  return (
    <label className="inline-flex items-center gap-2.5 cursor-pointer text-sm">
      <span
        className={`w-5 h-5 border-[1.5px] inline-flex items-center justify-center flex-shrink-0 rounded-[3px] transition-all duration-[120ms] cursor-pointer ${checked ? "bg-ink text-paper border-ink" : "bg-card border-line hover:border-accent"}`}
        onClick={onChange}
      >
        {checked && <span className="text-[13px] font-bold leading-none">✓</span>}
      </span>
      <span>{children}</span>
    </label>
  );
}
