"use client";

import Masthead    from "@/components/Masthead";
import Stepper     from "@/components/Stepper";
import ConnectPanel from "@/components/ConnectPanel";
import LoginPanel  from "@/components/LoginPanel";
import UrlStep     from "@/components/steps/UrlStep";
import DetectStep  from "@/components/steps/DetectStep";
import MatchStep   from "@/components/steps/MatchStep";
import PageStep    from "@/components/steps/PageStep";
import PreviewStep from "@/components/steps/PreviewStep";
import DoneStep    from "@/components/steps/DoneStep";
import { useStackshift, useStoreHydration } from "@/store";

export default function Home() {
  const hydrated        = useStoreHydration();
  const step            = useStackshift((s) => s.currentStep);
  const connectionOk    = useStackshift((s) => s.connectionOk);
  const configPanelOpen = useStackshift((s) => s.configPanelOpen);
  const setConfigPanelOpen = useStackshift((s) => s.setConfigPanelOpen);

  if (!hydrated) {
    return (
      <>
        <Masthead />
        <main className="px-12 py-14 max-w-[1400px] mx-auto animate-stage-in">
          <p className="font-mono text-[11px] tracking-[2px] uppercase text-muted mt-6">Loading…</p>
        </main>
      </>
    );
  }

  if (!connectionOk) {
    return (
      <>
        <Masthead />
        <main className="px-12 py-14 max-w-[1400px] mx-auto animate-stage-in">
          <LoginPanel />
        </main>
        <SiteFooter />
      </>
    );
  }

  return (
    <>
      <Masthead />
      <main className="px-12 py-14 max-w-[1400px] mx-auto animate-stage-in">
        <Stepper />
        {step === "url"     && <UrlStep />}
        {step === "detect"  && <DetectStep />}
        {step === "match"   && <MatchStep />}
        {step === "page"    && <PageStep />}
        {step === "preview" && <PreviewStep />}
        {step === "done"    && <DoneStep />}
      </main>

      {configPanelOpen && (
        <ConnectPanel mode="settings" onClose={() => setConfigPanelOpen(false)} />
      )}

      <SiteFooter />
    </>
  );
}

function SiteFooter() {
  return (
    <footer className="mt-20 px-12 py-10 border-t border-line font-mono text-[11px] text-muted flex justify-between tracking-[1.5px] uppercase flex-wrap gap-3">
      <span>Stackshift · Hackathon · Casual Coders</span>
      <span>Lift and shift, minus the shift.</span>
    </footer>
  );
}
